44	func GetWorkflows(client *api.Client, repo ghrepo.Interface, limit int) ([]Workflow, error) {
45	perPage := limit
46	page := 1
47	if limit > 100 || limit == 0 {
48	perPage = 100
49	}
50	
51	workflows := []Workflow{}
52	
53	for {
