60	
61	err := client.REST(repo.RepoHost(), "GET", path, nil, &result)
62	if err != nil {
63	return nil, err
64	}
65	
66	for _, workflow := range result.Workflows {
67	workflows = append(workflows, workflow)
68	if limit > 0 && len(workflows) == limit {
69	break
70	}
71	}
72	
73	if len(result.Workflows) < perPage {
74	break
75	}
76	
77	page++
78	}
79	
