104	var selected int
105	
106	err := prompt.SurveyAskOne(&survey.Select{
107	Message:  promptMsg,
108	Options:  candidates,
109	PageSize: 15,
110	}, &selected)
111	if err != nil {
112	return nil, err
113	}
114	
115	return &filtered[selected], nil
116	}
